import Blockly from 'blockly/core';
import blockDefs from './blockJson/BTList_motion.json';

const registerBlock = (def) => {
  if (!def || !def.type) return;
  Blockly.Blocks[def.type] = {
    init: function () {
      this.jsonInit(def);
      const tooltip = String(def.tooltip || '').trim();
      const comment = tooltip || String(def.x_description || '').trim();
      if (tooltip) {
        this.setTooltip(tooltip);
      }
      if (comment) {
        this.setCommentText(comment);
      }
    },
  };
};

(Array.isArray(blockDefs) ? blockDefs : []).forEach(registerBlock);

export { blockDefs as btListBlocksmotion };
